    },
    {
      "title": "Class XII Project (File Handling/SQL Connectivity)",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
      "chapter_name": "Computational Thinking and Programming – 2",
      "details": "Create something tangible and useful using Python file handling or Python-SQL connectivity. Work in groups of two to three students on a real-world problem (e.g., GST invoice generator, school software). Start at least 6 months before submission."
    }
  ],
  "practicals": [
    {
      "title": "Lab Test",
      "unit_name": "Unit No. 2: Computational Thinking and Programming - I",
      "chapter_name": "Computational Thinking and Programming - I",
      "details": "Python program (60% logic + 20% documentation + 20% code quality). Marks: 12."
    },
    {
      "title": "Report File + Viva",
      "unit_name": "Unit No. 2: Computational Thinking and Programming - I",
      "chapter_name": "Computational Thinking and Programming - I",
      "details": "Minimum 20 Python programs in report file; Viva voce. Marks: 10."
    },
    {
      "title": "Suggested Practical List (Class XI)",
      "unit_name": "Unit No. 2: Computational Thinking and Programming - I",
      "chapter_name": "Computational Thinking and Programming - I",
      "details": "Input welcome message; Input two/three numbers to find larger/smaller; Generate patterns using nested loops; Series summation programs (geometric, arithmetic); Check perfect/Armstrong/palindrome number; Prime/composite check; Fibonacci series; GCD/LCM calculation; Count vowels/consonants/case in string; String palindrome and case conversion; Find largest/smallest in list/tuple; Swap elements at even/odd locations; Search element in list/tuple; Create dictionary for student marks."
    },
    {
      "title": "Lab Test",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
      "chapter_name": "Computational Thinking and Programming – 2",
      "details": "Python program (60% logic + 20% documentation + 20% code quality) AND SQL queries (4 queries based on one or two tables). Marks: 12."
    },
    {
      "title": "Report File + Viva",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
      "chapter_name": "Computational Thinking and Programming – 2",
      "details": "Minimum 15 Python programs; Minimum 5 sets of SQL queries using one/two tables; Minimum 4 programs based on Python-SQL connectivity. Viva voce included."
    },
    {
      "title": "Suggested Practical List (Class XII)",
      "unit_name": "Unit 1: Computational Thinking and Programming – 2",
      "chapter_name": "Computational Thinking and Programming – 2",
      "details": "Read text file line by line; Count vowels/consonants in file; Remove lines containing 'a'; Create binary file (name/roll number) search/update marks; Random number generator (dice); Implement stack using list; Create CSV file with user-id/password."
    },
    {
      "title": "Database Management Practical",
      "unit_name": "Unit 3: Database Management",
      "chapter_name": "Database Management",
      "details": "Create student table and insert data. Implement ALTER, UPDATE, ORDER BY, DELETE commands. Use GROUP BY for min/max/sum/count/average. Integrate SQL with Python (import module, cursor operations)."
    }
  ]
}
